#### 3.3 `src/services/productService.ts` (NEW)

Three exported functions, each corresponding to one route handler:

**Function 1: `listProducts`**

```typescript
import { products } from "../data.js";
import { ServiceError } from "../errors.js";
import type { ProductFilters, ProductListResult, EnrichedProduct } from "../types.js";

export function listProducts(filters: ProductFilters): ProductListResult {
  let filtered = [...products];

  if (filters.category !== undefined) {
    filtered = filtered.filter((p) => p.category === filters.category);
  }

  if (filters.minPrice !== undefined) {
    filtered = filtered.filter((p) => p.price >= filters.minPrice!);
  }

  if (filters.maxPrice !== undefined) {
    filtered = filtered.filter((p) => p.price <= filters.maxPrice!);
  }

  const totalValue = filtered.reduce((sum, p) => sum + p.price * p.stock, 0);
  const avgPrice =
    filtered.length > 0
      ? filtered.reduce((sum, p) => sum + p.price, 0) / filtered.length
      : 0;

  return {
    products: filtered,
    summary: {
      count: filtered.length,
      totalInventoryValue: Math.round(totalValue * 100) / 100,
      averagePrice: Math.round(avgPrice * 100) / 100,
    },
  };
}
```

- **Accepts**: `ProductFilters` -- the route handler parses query strings into typed values and passes them here. The service does not know about `req.query`.
- **Returns**: `ProductListResult` -- the route handler sends this directly as JSON.
- **Throws**: Nothing (no error cases in the current logic).

**Function 2: `getProduct`**

```typescript
export function getProduct(id: number): EnrichedProduct {
  const product = products.find((p) => p.id === id);

  if (!product) {
    throw new ServiceError(404, "Product not found");
  }

  return {
    ...product,
    isLowStock: product.stock < 10,
    inventoryValue: Math.round(product.price * product.stock * 100) / 100,
  };
}
```

- **Accepts**: `id: number` (parsed from route param by the handler).
- **Returns**: `EnrichedProduct`.
- **Throws**: `ServiceError(404, "Product not found")` -- exact same message as current code.

**Function 3: `adjustProductStock`**

```typescript
export function adjustProductStock(id: number, adjustment: number): EnrichedProduct {
  const product = products.find((p) => p.id === id);

  if (!product) {
    throw new ServiceError(404, "Product not found");
  }

  if (typeof adjustment !== "number") {
    throw new ServiceError(400, "adjustment must be a number");
  }

  const newStock = product.stock + adjustment;
  if (newStock < 0) {
    throw new ServiceError(400, "Insufficient stock");
  }

  product.stock = newStock;

  return {
    ...product,
    isLowStock: product.stock < 10,
    inventoryValue: Math.round(product.price * product.stock * 100) / 100,
  };
}
```

- **Accepts**: `id: number`, `adjustment: number`.
- **Returns**: `EnrichedProduct`.
- **Throws**: `ServiceError(404)` or `ServiceError(400)` with exact messages matching current behavior.
- **Side effect**: Mutates `product.stock` in the `products` array (same as current code).

